import { validationResult } from 'express-validator';
import { sendError } from '../utils/response.js';

/**
 * Middleware to parse validation errors generated by express-validator.
 * Returns the first validation error in the standard JSON response format.
 */
export const validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    // Extract first error message and return standard response payload
    const firstErrorMessage = errors.array()[0].msg;
    return sendError(res, firstErrorMessage, 400);
  }
  next();
};

export default validate;
